RVAL 1 month),'%Y-%m')) AS `dm_ym_last`, (DATE_FORMAT(ADDDATE(`purchase_date`,INTERVAL 1 month),'%Y-%m')) AS `test_alvaro`, (case when DATE_FORMAT(`purchase_date`,'%U-%X') = DATE_FORMAT(CURRENT_DATE(),'%U-%X') then 1 else 0 end) AS `dm_current_week_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(CURRENT_DATE(),'%Y-%m') then 1 else 0 END) AS `current_month _flag`, (CASE WHEN (`purchase_date`) >  (CURDATE()-(7+DAYOFWEEK(CURDATE()))) AND (WEEK(`purchase_date`) != WEEK(CURDATE())) THEN 1 ELSE 0 END) AS `dm_last_week_flag`, (CASE WHEN DATE(`purchase_date`) > (CURDATE() - 14 - DAYOFWEEK(CURDATE())) and DATE(`purchase_date`) <= (CURDATE() - 7 - DAYOFWEEK(CURDATE())) THEN 1 ELSE 0 END) AS `dm_prior_week_flag`, (case when year(`purchase_date`) = (year(CURDATE())-1) and week(`purchase_date`) = (week(CURDATE())-1) then 1 else 0 END) AS `dm_last_week_last_year_flag`, (DATEDIFF(`dm_current_date`, `purchase_date`)) AS `dm_relative_date`, (case when DAYOFWEEK(`purchase_date`) = DAYOFWEEK(`dm_current_date`) then 1 else 0 END) AS `dm_sdow_flag`, (case when `purchase_date` = `dm_current_date` then 1 else 0 END) AS `dm_today_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(`dm_current_date`,'%Y-%m') then 1 else 0 END) AS `dm_current_month_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(DATE_SUB(`dm_current_date`,INTERVAL 1 month),'%Y-%m') then 1 else 0 END) AS `dm_last_month_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(DATE_SUB(`dm_current_date`,INTERVAL 2 month),'%Y-%m') then 1 else 0 END) AS `dm_prior_month_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(DATE_SUB(`dm_current_date`,INTERVAL 12 month),'%Y-%m') then 1 else 0 END) AS `dm_last_year_month_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(DATE_SUB(`dm_current_date`,INTERVAL 13 month),'%Y-%m') then 1 else 0 END) AS `dm_prior_year_month_flag`, (case when year(`purchase_date`) = year(`dm_current_date`) and DAYOFYEAR(`purchase_date`) < DAYOFYEAR(`dm_current_date`) then 1 else 0 END) AS `dm_ytd_flag`, (case when year(`purchase_date`) = year(DATE_SUB(`dm_current_date`,INTERVAL 12 month)) and DAYOFYEAR(`purchase_date`) < DAYOFYEAR(`dm_current_date`) then 1 else 0 END) AS `dm_last_ytd_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(`dm_current_date`,'%Y-%m') and DAYOFMONTH(`purchase_date`) < DAYOFMONTH(`dm_current_date`) then 1 else 0 END) AS `dm_mtd_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(DATE_SUB(`dm_current_date`,INTERVAL 1 month),'%Y-%m') and DAYOFMONTH(`purchase_date`) < DAYOFMONTH(`dm_current_date`) then 1 else 0 END) AS `dm_last_mtd_flag`, (case when DATE_FORMAT(`purchase_date`,'%Y-%m') = DATE_FORMAT(DATE_SUB(`dm_current_date`,INTERVAL 12 month),'%Y-%m') and DAYOFMONTH(`purchase_date`) < DAYOFMONTH(`dm_current_date`) then 1 else 0 END) AS `dm_last_year_mtd_flag`, (case when year(`purchase_date`) = year(`dm_current_date`) then 1 else 0 END) AS `dm_current_year_flag`, (case when year(`purchase_date`) = YEAR(DATE_SUB(`dm_current_date`,INTERVAL 12 month)) then 1 else 0 END) AS `dm_last_year_flag`, (case when `purchase_date` >= DATE_SUB(`dm_current_date`,INTERVAL 11 month) then 1 else 0 END) AS `dm_last_12m_flag`, (case when `purchase_date` >= DATE_SUB(`dm_current_date`,INTERVAL 23 month) and `purchase_date` <= DATE_SUB(`dm_current_date`,INTERVAL 12 month) then 1 else 0 END) AS `dm_prior_12m_flag`, (DAYOFYEAR(`dm_current_date`) ) AS `dm_day_of_year`, (case when `dm_relative_date` = 1 then 1 else 0 END) AS `dm_yesterday_flag`, (case when `dm_relative_date` = 7 then 1 else 0 END) AS `dm_sdlw_flag`, (case when `dm_relative_date` <= 7 and `dm_relative_date` >= 1 then 1 else 0 END) AS `dm_last_07_flag`, (case when `dm_relative_date` <= 14 and `dm_relative_date` >= 8 then 1 else 0 END) AS `dm_prior_07_flag`, (case when `dm_relative_date` <= 28 and `dm_relative_date` >= 1 then 1 else 0 END) AS `dm_last_28_flag`, (case when `dm_relative_date` = 2 then 1 else 0 END) AS `dm_prior_day_flag`, (case when `dm_relative_date` = 1 then `purchase_date` END) AS `dm_yesterday_date`, (case when `dm_relative_date` = 2 then `purchase_date` END) AS `dm_priorday_date` FROM _Join_Data_3
