brand_created_at` THEN 'Pro Forma'  /*Sales before the first appearece of the brands' catalog*/ WHEN `purchase_date` < `seller_created_at` THEN 'Pro Forma'  /*Sales before the first appearece of new seller*/ WHEN  `purchase_date` >= `brand_created_at` THEN 'Recom' WHEN  `purchase_date` >= `seller_created_at` THEN 'Recom' ELSE 'Not Identified' END) AS `Revenue Flag` FROM _Join_Data_9
),

_Filter_Rows AS (
  SELECT * FROM _Segments WHERE `purchase_date` >= DATE_SUB(`purchase_date`,INTERVAL 3 month)
),

_Group_By_1 AS (
  SELECT `country_id`, `asin`, `brand name`, `partner name`, SUM(`sales`) AS `sales` FROM _Filter_Rows GROUP BY `country_id`, `asin`, `brand name`, `partner name`
),

_Rank_Window AS (
  SELECT *, RANK() OVER (PARTITION BY `country_id`, `brand name`, `partner name` ORDER BY `sales` DESC) AS `sales_rank_3mth` FROM _Group_By_1
),

